package org.eclipse.rdf4j.query.algebra.evaluation.impl.evaluationsteps;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.Arrays;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.QueryEvaluationContext;
import org.eclipse.rdf4j.query.explanation.TelemetryMetricNames;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.eclipse.rdf4j.query.impl.ListBindingSet;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

class BindingSetAssignmentQueryEvaluationStepTest {

	@Test
	void skipsBindingsProvidedMetricWhenRuntimeTelemetryDisabled() {
		CountingBindingSetAssignment assignment = assignment("x", "1", "2");
		BindingSetAssignmentQueryEvaluationStep step = new BindingSetAssignmentQueryEvaluationStep(assignment,
				new QueryEvaluationContext.Minimal(null));

		assertThat(results(step.evaluate(EmptyBindingSet.getInstance()))).hasSize(2);

		assertThat(assignment.peekLongMetricActual(TelemetryMetricNames.BINDINGS_PROVIDED_ACTUAL)).isEqualTo(-1L);
		assertThat(assignment.longMetricReadCount).isZero();
		assertThat(assignment.longMetricWriteCount).isZero();
	}

	@Test
	void recordsBindingsProvidedMetricWhenRuntimeTelemetryEnabled() {
		BindingSetAssignment assignment = assignment("x", "1", "2");
		assignment.setRuntimeTelemetryEnabled(true);
		BindingSetAssignmentQueryEvaluationStep step = new BindingSetAssignmentQueryEvaluationStep(assignment,
				new QueryEvaluationContext.Minimal(null));

		assertThat(results(step.evaluate(EmptyBindingSet.getInstance()))).hasSize(2);

		assertThat(assignment.getLongMetricActual(TelemetryMetricNames.BINDINGS_PROVIDED_ACTUAL)).isEqualTo(2L);
	}

	@Test
	void skipsPerRowParentValueLookupForUnboundAssignmentNames() {
		Value parentValue = SimpleValueFactory.getInstance().createLiteral("parent");
		CountingBindingSet parent = new CountingBindingSet();
		parent.addBinding("a", parentValue);
		BindingSetAssignment assignment = assignment("b", "1", "2");
		BindingSetAssignmentQueryEvaluationStep step = new BindingSetAssignmentQueryEvaluationStep(assignment,
				new QueryEvaluationContext.Minimal(null));

		List<BindingSet> results = results(step.evaluate(parent));

		assertThat(results).hasSize(2);
		assertThat(results).allSatisfy(result -> {
			assertThat(result.getValue("a")).isEqualTo(parentValue);
			assertThat(result.getValue("b")).isNotNull();
		});
		assertThat(parent.valueReadCount("b")).isZero();
		assertThat(parent.hasBindingReadCount("b")).isEqualTo(1);
	}

	@Test
	void emptyRowPassesIncomingBindingsThroughWhenNamesOverlap() {
		// Found by the equivalence differential fuzzer: incoming bindings overlapping the VALUES
		// names route evaluation through the compatibility-checked path, which used to drop the
		// empty row instead of joining it as the identity mapping.
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(Set.of("x"));
		assignment.setBindingSets(List.of(new MapBindingSet()));
		BindingSetAssignmentQueryEvaluationStep step = new BindingSetAssignmentQueryEvaluationStep(assignment,
				new QueryEvaluationContext.Minimal(null));
		BindingSet incoming = binding("x", "bound");

		List<BindingSet> results = results(step.evaluate(incoming));

		assertThat(results).containsExactly(incoming);
	}

	@Test
	void allUndefRowBehavesLikeTheEmptyRow() {
		// A row whose declared columns are all UNDEF (name with null value, e.g. a parser-built
		// ListBindingSet) is equal to the empty row and must evaluate identically.
		BindingSetAssignment undefRepresentation = new BindingSetAssignment();
		undefRepresentation.setBindingNames(Set.of("x"));
		undefRepresentation.setBindingSets(List.of(new ListBindingSet(List.of("x"), Arrays.asList((Value) null))));
		BindingSetAssignment emptyRepresentation = new BindingSetAssignment();
		emptyRepresentation.setBindingNames(Set.of("x"));
		emptyRepresentation.setBindingSets(List.of(new MapBindingSet()));
		BindingSet incoming = binding("x", "bound");

		List<BindingSet> undefResults = results(new BindingSetAssignmentQueryEvaluationStep(undefRepresentation,
				new QueryEvaluationContext.Minimal(null)).evaluate(incoming));
		List<BindingSet> emptyResults = results(new BindingSetAssignmentQueryEvaluationStep(emptyRepresentation,
				new QueryEvaluationContext.Minimal(null)).evaluate(incoming));

		assertThat(undefResults).isEqualTo(emptyResults);
	}

	@Test
	void undefColumnsDoNotLeakIntoResultsWithoutIncomingBindings() {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(Set.of("x", "y"));
		assignment.setBindingSets(List.of(new ListBindingSet(
				List.of("x", "y"),
				Arrays.asList(SimpleValueFactory.getInstance().createLiteral("v"), null))));
		BindingSetAssignmentQueryEvaluationStep step = new BindingSetAssignmentQueryEvaluationStep(assignment,
				new QueryEvaluationContext.Minimal(null));

		List<BindingSet> results = results(step.evaluate(EmptyBindingSet.getInstance()));

		assertThat(results).hasSize(1);
		assertThat(results.get(0).getBindingNames()).containsExactly("x");
	}

	private static List<BindingSet> results(CloseableIteration<BindingSet> iteration) {
		try (iteration) {
			return iteration.stream().toList();
		}
	}

	private static CountingBindingSetAssignment assignment(String bindingName, String... values) {
		CountingBindingSetAssignment assignment = new CountingBindingSetAssignment();
		assignment.setBindingSets(List.of(values)
				.stream()
				.map(value -> binding(bindingName, value))
				.toList());
		return assignment;
	}

	private static BindingSet binding(String bindingName, String value) {
		MapBindingSet bindingSet = new MapBindingSet();
		bindingSet.addBinding(bindingName, SimpleValueFactory.getInstance().createLiteral(value));
		return bindingSet;
	}

	private static final class CountingBindingSetAssignment extends BindingSetAssignment {
		private int longMetricReadCount;
		private int longMetricWriteCount;

		@Override
		public long getLongMetricActual(String metricName) {
			longMetricReadCount++;
			return super.getLongMetricActual(metricName);
		}

		@Override
		public void setLongMetricActual(String metricName, long metricValue) {
			longMetricWriteCount++;
			super.setLongMetricActual(metricName, metricValue);
		}

		private long peekLongMetricActual(String metricName) {
			return super.getLongMetricActual(metricName);
		}
	}

	private static final class CountingBindingSet extends MapBindingSet {
		private final Map<String, Integer> valueReadCounts = new HashMap<>();
		private final Map<String, Integer> hasBindingReadCounts = new HashMap<>();

		@Override
		public Value getValue(String bindingName) {
			valueReadCounts.merge(bindingName, 1, Integer::sum);
			return super.getValue(bindingName);
		}

		@Override
		public boolean hasBinding(String bindingName) {
			hasBindingReadCounts.merge(bindingName, 1, Integer::sum);
			return super.hasBinding(bindingName);
		}

		private int valueReadCount(String bindingName) {
			return valueReadCounts.getOrDefault(bindingName, 0);
		}

		private int hasBindingReadCount(String bindingName) {
			return hasBindingReadCounts.getOrDefault(bindingName, 0);
		}
	}
}
